1	/**
2	 * lab.commission-post-xguild / lab.wait-for-writ-terminal-xguild —
3	 * cross-guild scenario engines for trial workloads.
4	 *
5	 * The canonical trial scenario is "post a commission to the test guild
6	 * and wait for it to complete." `lab.commission-post-xguild` does both
7	 * inline by default (single engine fits the rig template's single-
8	 * scenario-engine slot), and `lab.wait-for-writ-terminal-xguild` is the
9	 * standalone wait building block — useful for future multi-step
10	 * scenarios where post is detached from wait.
11	 *
12	 * v1 cross-guild surface is shell-out via
13	 * `<testGuild>/node_modules/.bin/nsg --guild-root <test-guild> ...` —
14	 * the test guild's locally-installed CLI, version-matched to the
15	 * test guild's `nexus` field. lab.guild-setup bootstraps that
16	 * install via `npx -p @shardworks/nexus@<spec> nsg init …`. The
17	 * real cross-guild engine surface is parked at click c-mom9vm3n for
18	 * v2.
19	 *
20	 * COMMISSION-POST FLOW
21	 * ────────────────────
22	 * 1. Validate givens (briefPath absolute; type defaults to 'mandate').
23	 * 2. Discover the target test guild from `context.upstream` — duck-type
24	 *    detection: any upstream yield with `{guildName: string, guildPath:
25	 *    string}` (the guild-fixture's yield shape).
26	 * 3. Read brief content from briefPath. Title defaults to the brief's
27	 *    first markdown H1 if present, else "Commission from <basename>".
28	 * 4. Shell out: `nsg --guild-root <testGuild> commission-post --title
29	 *    <title> --body <body> --type <type> [--parent-id <parentId>]`.
30	 *    Parse JSON response, extract writ id.
31	 * 5. If `waitForTerminal !== false` (default true), poll until the writ
32	 *    reaches a terminal state. Otherwise return immediately after post.
33	 *
34	 * GIVENS (commission-post)
35	 * ────────────────────────
36	 *   briefPath        : string  — absolute path to the brief markdown.
37	 *   title            : string? — optional explicit title; defaults to
38	 *                                first H1 of the brief, or
39	 *                                "Commission from <basename>".
40	 *   type             : string? — writ type, default 'mandate'.
41	 *   parentId         : string? — optional parent writ id (in the test
42	 *                                guild's namespace).
43	 *   waitForTerminal  : bool?   — default true. When true, the engine
44	 *                                polls until writ terminal before
45	 *                                returning. When false, returns
46	 *                                immediately after post.
47	 *   pollIntervalMs   : number? — only meaningful when waiting; default
48	 *                                5000.
49	 *   timeoutMs        : number? — only meaningful when waiting; default
50	 *                                1_800_000 (30 minutes).
51	 *
52	 * YIELDS (commission-post)
53	 * ────────────────────────
54	 *   waitForTerminal=true:
55	 *     { writId, postedAt, finalState, resolution, resolvedAt }
56	 *   waitForTerminal=false:
57	 *     { writId, postedAt }
58	 *
59	 * GIVENS (wait-for-writ-terminal — standalone)
60	 * ────────────────────────────────────────────
61	 *   writId           : string  — the writ id to poll.
62	 *   pollIntervalMs   : number? — default 5000.
63	 *   timeoutMs        : number? — default 1_800_000 (30 minutes).
64	 *
65	 * YIELDS (wait-for-writ-terminal)
66	 * ───────────────────────────────
67	 *   { writId, finalState, resolution, resolvedAt }
68	 */
69	
70	import { execFile as execFileCb } from 'node:child_process';
71	import { promisify } from 'node:util';
72	import { existsSync } from 'node:fs';
73	import { readFile } from 'node:fs/promises';
74	import path from 'node:path';
75	import type {
76	  EngineDesign,
77	  EngineRunContext,
78	  EngineRunResult,
79	} from '@shardworks/fabricator-apparatus';
80	
81	const execFile = promisify(execFileCb);
82	
83	// ── Defaults ──────────────────────────────────────────────────────────
84	
85	export const DEFAULT_POLL_INTERVAL_MS = 5_000;
86	export const DEFAULT_TIMEOUT_MS = 30 * 60 * 1_000; // 30 minutes
87	const TERMINAL_CLASSIFICATION = 'terminal';
88	
89	// ── Types ─────────────────────────────────────────────────────────────
90	
91	export interface DiscoveredTestGuild {
92	  guildName: string;
93	  guildPath: string;
94	}
95	
96	interface PostedWrit {
97	  writId: string;
98	  postedAt: string;
99	}
100	
101	interface TerminalSnapshot {
102	  writId: string;
103	  finalState: string;
104	  resolution: string | null;
105	  resolvedAt: string;
106	}
107	
108	// ── Helpers ───────────────────────────────────────────────────────────
109	
110	/**
111	 * Walk upstream yields and find every entry that looks like a
112	 * guild-fixture's output (has both `guildName` and `guildPath` strings).
113	 * Same duck-typing pattern as the codex discovery in guild-fixture.
114	 */
115	export function discoverTestGuilds(
116	  upstream: Record<string, unknown>,
117	): DiscoveredTestGuild[] {
118	  const result: DiscoveredTestGuild[] = [];
119	  for (const value of Object.values(upstream)) {
120	    if (
121	      typeof value === 'object' &&
122	      value !== null &&
123	      !Array.isArray(value)
124	    ) {
125	      const obj = value as Record<string, unknown>;
126	      if (typeof obj.guildName === 'string' && typeof obj.guildPath === 'string') {
127	        result.push({ guildName: obj.guildName, guildPath: obj.guildPath });
128	      }
129	    }
130	  }
131	  return result;
132	}
133	
134	/**
135	 * Pull the first markdown H1 ("# Title") out of a brief, returning the
136	 * title text. Returns null when no H1 found.
137	 */
138	export function extractH1Title(briefContent: string): string | null {
139	  const match = briefContent.match(/^#\s+(.+?)\s*$/m);
140	  return match ? match[1]!.trim() : null;
141	}
142	
143	async function exec(
144	  cmd: string,
145	  args: string[],
146	): Promise<{ stdout: string; stderr: string }> {
147	  try {
148	    const { stdout, stderr } = await execFile(cmd, args, {
149	      maxBuffer: 50 * 1024 * 1024,
150	    });
151	    return { stdout: stdout.trim(), stderr: stderr.trim() };
152	  } catch (err: unknown) {
153	    const e = err as { stderr?: string; message?: string };
154	    throw new Error(
155	      `${cmd} ${args.join(' ')} failed: ${e.stderr || e.message || 'unknown error'}`,
156	    );
157	  }
158	}
159	
160	/**
161	 * Resolve the test guild's locally-installed `nsg` binstub.
162	 *
163	 * The cross-guild shellouts always run against the test guild's own
164	 * CLI — version-matched to the test guild's `nexus` field, no
165	 * dependency on whatever CLI happens to be on PATH. lab.guild-setup
166	 * bootstraps the install via `npx -p @shardworks/nexus@<spec> nsg
167	 * init …`, so the binstub exists by the time any scenario engine
168	 * runs.
169	 */
170	export function resolveLocalNsg(testGuildPath: string, designId: string): string {
171	  const localNsg = path.join(testGuildPath, 'node_modules', '.bin', 'nsg');
172	  if (!existsSync(localNsg)) {
173	    throw new Error(
174	      `[${designId}] no local nsg at ${localNsg}. The test guild must have been ` +
175	        `bootstrapped via lab.guild-setup (which installs @shardworks/nexus locally). ` +
176	        `If you're invoking this engine outside the laboratory's standard rig, ensure ` +
177	        `the test guild's package.json declares @shardworks/nexus and that npm install ran.`,
178	    );
179	  }
180	  return localNsg;
181	}
182	
183	/**
184	 * Resolve the single test guild from upstream yields. Throws when zero
185	 * or multiple test guilds are present — explicit selection is future
186	 * work (v2).
187	 */
188	function resolveTestGuild(
189	  upstream: Record<string, unknown>,
190	  designId: string,
191	): DiscoveredTestGuild {
192	  const guilds = discoverTestGuilds(upstream);
193	  if (guilds.length === 0) {
194	    throw new Error(
195	      `[${designId}] no test guild found in context.upstream — the engine ` +
196	        `expects at least one upstream yield with {guildName: string, guildPath: string} ` +
197	        `(the guild-fixture's yield shape).`,
198	    );
199	  }
200	  if (guilds.length > 1) {
201	    const names = guilds.map((g) => g.guildName).join(', ');
202	    throw new Error(
203	      `[${designId}] multiple test guilds found in context.upstream (${names}); ` +
204	        `explicit selection is not yet supported in v1.`,
205	    );
206	  }
207	  return guilds[0]!;
208	}
209	
210	/**
211	 * Poll until the target writ reaches a terminal-classification state.
212	 * Throws on timeout. Each poll shells out `nsg --guild-root <test-guild>
213	 * writ show --id <writId> --format json`.
214	 *
215	 * Exposed as a standalone helper so both engines (the post-and-wait
216	 * happy path, and the standalone wait engine) share its behavior.
217	 */
218	export async function waitForWritTerminal(opts: {
219	  testGuildPath: string;
220	  writId: string;
221	  pollIntervalMs: number;
222	  timeoutMs: number;
223	  designId: string;
224	}): Promise<TerminalSnapshot> {
225	  const startedAt = Date.now();
226	  while (true) {
227	    const elapsed = Date.now() - startedAt;
228	    if (elapsed > opts.timeoutMs) {
229	      throw new Error(
230	        `[${opts.designId}] timed out after ${opts.timeoutMs}ms waiting for writ ` +
231	          `${opts.writId} (test guild ${opts.testGuildPath}) to reach a terminal state.`,
232	      );
233	    }
234	
235	    const localNsg = resolveLocalNsg(opts.testGuildPath, opts.designId);
236	    // `writ show` is a sub-subcommand of the `writ` group in the
237	    // published 0.1.292 CLI surface — there is no top-level
238	    // `writ-show` command. Earlier drafts of this engine (and a
239	    // few of the engine docstrings) referred to `writ-show`; that
240	    // was always wrong and only escaped notice because phase-1/2a
241	    // trials all ran with `waitForTerminal: false` and never
242	    // exercised this poll path. Phase 2b is the first trial to
243	    // hit it and surfaced the typo.
244	    const { stdout } = await exec(localNsg, [
245	      '--guild-root',
246	      opts.testGuildPath,
247	      'writ',
248	      'show',
249	      '--id',
250	      opts.writId,
251	      '--format',
252	      'json',
253	    ]);
254	
255	    let parsed: unknown;
256	    try {
257	      parsed = JSON.parse(stdout);
258	    } catch (err) {
259	      throw new Error(
260	        `[${opts.designId}] writ-show JSON parse failed for writ ${opts.writId}: ` +
261	          `${(err as Error).message}; stdout=${stdout.slice(0, 200)}`,
262	      );
263	    }
264	
265	    if (typeof parsed !== 'object' || parsed === null) {
266	      throw new Error(
267	        `[${opts.designId}] writ-show response was not an object for writ ${opts.writId}.`,
268	      );
269	    }
270	
271	    const obj = parsed as Record<string, unknown>;
272	    const classification = obj.classification;
273	    if (classification === TERMINAL_CLASSIFICATION) {
274	      return {
275	        writId: opts.writId,
276	        finalState: typeof obj.phase === 'string' ? obj.phase : 'unknown',
277	        resolution: typeof obj.resolution === 'string' ? obj.resolution : null,
278	        resolvedAt:
279	          typeof obj.resolvedAt === 'string' ? obj.resolvedAt : new Date().toISOString(),
280	      };
281	    }
282	
283	    await new Promise((resolve) => setTimeout(resolve, opts.pollIntervalMs));
284	  }
285	}
286	
287	// ── Validation helpers ────────────────────────────────────────────────
288	
289	function requireAbsolutePath(
290	  value: unknown,
291	  designId: string,
292	  fieldName: string,
293	): string {
294	  if (typeof value !== 'string' || !path.isAbsolute(value)) {
295	    throw new Error(
296	      `[${designId}] givens.${fieldName} must be an absolute path; got "${String(value)}".`,
297	    );
298	  }
299	  return value;
300	}
301	
302	function optionalString(
303	  value: unknown,
304	  designId: string,
305	  fieldName: string,
306	): string | undefined {
307	  if (value === undefined || value === null) return undefined;
308	  if (typeof value !== 'string') {
309	    throw new Error(
310	      `[${designId}] givens.${fieldName} must be a string when provided; got ${typeof value}.`,
311	    );
312	  }
313	  return value;
314	}
315	
316	function optionalPositiveNumber(
317	  value: unknown,
318	  designId: string,
319	  fieldName: string,
320	  fallback: number,
321	): number {
322	  if (value === undefined || value === null) return fallback;
323	  if (typeof value !== 'number' || !Number.isFinite(value) || value <= 0) {
324	    throw new Error(
325	      `[${designId}] givens.${fieldName} must be a positive number when provided; got ${String(value)}.`,
326	    );
327	  }
328	  return value;
329	}
330	
331	// ── Commission-post engine ────────────────────────────────────────────
332	
333	export const commissionPostXguildEngine: EngineDesign = {
334	  id: 'lab.commission-post-xguild',
335	  async run(rawGivens, context: EngineRunContext): Promise<EngineRunResult> {
336	    const designId = 'lab.commission-post-xguild';
337	    const briefPath = requireAbsolutePath(rawGivens.briefPath, designId, 'briefPath');
338	    const explicitTitle = optionalString(rawGivens.title, designId, 'title');
339	    const type = optionalString(rawGivens.type, designId, 'type') ?? 'mandate';
340	    const parentId = optionalString(rawGivens.parentId, designId, 'parentId');
341	    const waitForTerminal = rawGivens.waitForTerminal !== false; // default true
342	    const pollIntervalMs = optionalPositiveNumber(
343	      rawGivens.pollIntervalMs,
344	      designId,
345	      'pollIntervalMs',
346	      DEFAULT_POLL_INTERVAL_MS,
347	    );
348	    const timeoutMs = optionalPositiveNumber(
349	      rawGivens.timeoutMs,
350	      designId,
351	      'timeoutMs',
352	      DEFAULT_TIMEOUT_MS,
353	    );
354	
355	    const testGuild = resolveTestGuild(context.upstream, designId);
356	
357	    // Read brief.
358	    let briefContent: string;
359	    try {
360	      briefContent = await readFile(briefPath, 'utf8');
361	    } catch (err) {
362	      throw new Error(
363	        `[${designId}] failed to read brief at ${briefPath}: ${(err as Error).message}`,
364	      );
365	    }
366	
367	    const title =
368	      explicitTitle ?? extractH1Title(briefContent) ?? `Commission from ${path.basename(briefPath)}`;
369	
370	    // Post commission via shell-out.
371	    const args = [
372	      '--guild-root',
373	      testGuild.guildPath,
374	      'commission-post',
375	      '--title',
376	      title,
377	      '--body',
378	      briefContent,
379	      '--type',
380	      type,
381	    ];
382	    if (parentId !== undefined) {
383	      args.push('--parent-id', parentId);
384	    }
385	
386	    const localNsg = resolveLocalNsg(testGuild.guildPath, designId);
387	    const { stdout } = await exec(localNsg, args);
388	    let writ: unknown;
389	    try {
390	      writ = JSON.parse(stdout);
391	    } catch (err) {
392	      throw new Error(
393	        `[${designId}] commission-post JSON parse failed: ${(err as Error).message}; ` +
394	          `stdout=${stdout.slice(0, 200)}`,
395	      );
396	    }
397	    if (typeof writ !== 'object' || writ === null) {
398	      throw new Error(
399	        `[${designId}] commission-post response was not an object: ${stdout.slice(0, 200)}`,
400	      );
401	    }
402	    const writObj = writ as Record<string, unknown>;
403	    if (typeof writObj.id !== 'string' || writObj.id.length === 0) {
404	      throw new Error(
405	        `[${designId}] commission-post response had no writ id; stdout=${stdout.slice(0, 200)}`,
406	      );
407	    }
408	
409	    const posted: PostedWrit = {
410	      writId: writObj.id,
411	      postedAt: new Date().toISOString(),
412	    };
413	
414	    if (!waitForTerminal) {
415	      return {
416	        status: 'completed',
417	        yields: posted,
418	      };
419	    }
420	
421	    // Inline wait until terminal.
422	    const terminal = await waitForWritTerminal({
423	      testGuildPath: testGuild.guildPath,
424	      writId: posted.writId,
425	      pollIntervalMs,
426	      timeoutMs,
427	      designId,
428	    });
429	
430	    return {
431	      status: 'completed',
432	      yields: { ...posted, ...terminal },
433	    };
434	  },
435	};
436	
437	// ── Standalone wait engine ────────────────────────────────────────────
438	
439	export const waitForWritTerminalXguildEngine: EngineDesign = {
440	  id: 'lab.wait-for-writ-terminal-xguild',
441	  async run(rawGivens, context: EngineRunContext): Promise<EngineRunResult> {
442	    const designId = 'lab.wait-for-writ-terminal-xguild';
443	    const writId = optionalString(rawGivens.writId, designId, 'writId');
444	    if (writId === undefined || writId.length === 0) {
445	      throw new Error(
446	        `[${designId}] givens.writId is required (the writ id to poll in the test guild).`,
447	      );
448	    }
449	    const pollIntervalMs = optionalPositiveNumber(
450	      rawGivens.pollIntervalMs,
451	      designId,
452	      'pollIntervalMs',
453	      DEFAULT_POLL_INTERVAL_MS,
454	    );
455	    const timeoutMs = optionalPositiveNumber(
456	      rawGivens.timeoutMs,
457	      designId,
458	      'timeoutMs',
459	      DEFAULT_TIMEOUT_MS,
460	    );
461	
462	    const testGuild = resolveTestGuild(context.upstream, designId);
463	    const terminal = await waitForWritTerminal({
464	      testGuildPath: testGuild.guildPath,
465	      writId,
466	      pollIntervalMs,
467	      timeoutMs,
468	      designId,
469	    });
470	
471	    return {
