1	/**
2	 * lab.probe-git-range — captures every commit between a codex's
3	 * recorded base SHA and its current head, writes one row per commit
4	 * to `lab-trial-codex-commits`. Big-diff tripwire: any single diff
5	 * over 10MB fails the probe (and thus the trial).
6	 *
7	 * The probe runs in the lab-host process and discovers the trial's
8	 * codex via duck-typing on `context.upstream` — any yield with the
9	 * `{codexName, bareLocalPath, baseSha}` shape (the codex-fixture's
10	 * yield form) is a candidate. A single matching codex is required
11	 * unless an explicit `codexName` given is supplied.
12	 *
13	 * Head SHA resolution: we read the bare repo's `main` ref, since the
14	 * bare is the canonical write target — the test guild seals into the
15	 * bare via the codexes plugin's seal flow. The codex-fixture's yield
16	 * carries `headSha = baseSha` at setup time; that field is not
17	 * updated as the trial progresses, so we re-read from the bare.
18	 *
19	 * GIVENS
20	 * ──────
21	 *   trialId    : string?  — Optional; falls back to `_trial.writId`.
22	 *   codexName  : string?  — Optional explicit codex selector. Required
23	 *                          when more than one codex is present in
24	 *                          upstream.
25	 *
26	 * SUMMARY (yields → archive row)
27	 * ──────────────────────────────
28	 *   {
29	 *     codexName       : string,
30	 *     baseSha         : string,
31	 *     headSha         : string,
32	 *     commitCount     : number,
33	 *     totalDiffBytes  : number,
34	 *     capturedAt      : string,
35	 *   }
36	 *
37	 * EXTRACT
38	 * ───────
39	 *   `<targetDir>/codex-history/`
40	 *     ├── commits-manifest.yaml      // ordered metadata
41	 *     └── NNNN-<sha-12>.patch        // one file per commit
42	 */
43	
44	import { execFile as execFileCb } from 'node:child_process';
45	import { promisify } from 'node:util';
46	import { writeFile, mkdir } from 'node:fs/promises';
47	import path from 'node:path';
48	import { stringify as yamlStringify } from 'yaml';
49	import { guild, generateId } from '@shardworks/nexus-core';
50	import type {
51	  EngineRunContext,
52	  EngineRunResult,
53	} from '@shardworks/fabricator-apparatus';
54	import type {
55	  Book,
56	  ReadOnlyBook,
57	  StacksApi,
58	} from '@shardworks/stacks-apparatus';
59	import type { InjectedTrialContext } from '../engines/phases.ts';
60	import {
61	  LAB_TRIAL_CODEX_COMMITS_BOOK,
62	  PER_DIFF_BYTE_CAP,
63	  type LabTrialCodexCommit,
64	} from '../archive/codex-commits-book.ts';
65	import type {
66	  ProbeEngineDesign,
67	  ProbeExtractArgs,
68	  ProbeExtractResult,
69	} from './types.ts';
70	
71	const execFile = promisify(execFileCb);
72	
73	const DESIGN_ID = 'lab.probe-git-range';
74	const EXTRACT_SUBDIR = 'codex-history';
75	const COMMITS_MANIFEST_FILE = 'commits-manifest.yaml';
76	
77	// ── Givens ────────────────────────────────────────────────────────────
78	
79	interface ResolvedGivens {
80	  trialId: string;
81	  codexName?: string;
82	}
83	
84	function validateGivens(rawGivens: Record<string, unknown>): ResolvedGivens {
85	  let trialId = rawGivens.trialId;
86	  if (trialId === undefined || trialId === null) {
87	    const trial = rawGivens._trial as InjectedTrialContext | undefined;
88	    if (trial && typeof trial.writId === 'string' && trial.writId.length > 0) {
89	      trialId = trial.writId;
90	    }
91	  }
92	  if (typeof trialId !== 'string' || trialId.length === 0) {
93	    throw new Error(
94	      `[${DESIGN_ID}] trialId is required (givens.trialId or framework-injected _trial.writId).`,
95	    );
96	  }
97	
98	  let codexName: string | undefined;
99	  if (rawGivens.codexName !== undefined && rawGivens.codexName !== null) {
100	    if (typeof rawGivens.codexName !== 'string' || rawGivens.codexName.length === 0) {
101	      throw new Error(`[${DESIGN_ID}] givens.codexName must be a non-empty string when provided.`);
102	    }
103	    codexName = rawGivens.codexName;
104	  }
105	
106	  return { trialId, codexName };
107	}
108	
109	// ── Codex discovery from upstream ────────────────────────────────────
110	
111	export interface DiscoveredCodexFixture {
112	  codexName: string;
113	  bareLocalPath: string;
114	  baseSha: string;
115	}
116	
117	/**
118	 * Walk upstream yields and find every entry that looks like a
119	 * codex-fixture's setup yield (has `codexName`, `bareLocalPath`,
120	 * `baseSha`). Same duck-typing pattern other engines use.
121	 */
122	export function discoverCodexFixtures(
123	  upstream: Record<string, unknown>,
124	): DiscoveredCodexFixture[] {
125	  const result: DiscoveredCodexFixture[] = [];
126	  for (const value of Object.values(upstream)) {
127	    if (
128	      typeof value === 'object' &&
129	      value !== null &&
130	      !Array.isArray(value)
131	    ) {
132	      const obj = value as Record<string, unknown>;
133	      if (
134	        typeof obj.codexName === 'string' &&
135	        typeof obj.bareLocalPath === 'string' &&
136	        typeof obj.baseSha === 'string'
137	      ) {
138	        result.push({
139	          codexName: obj.codexName,
140	          bareLocalPath: obj.bareLocalPath,
141	          baseSha: obj.baseSha,
142	        });
143	      }
144	    }
145	  }
146	  return result;
147	}
148	
149	function selectCodex(
150	  upstream: Record<string, unknown>,
151	  explicitName: string | undefined,
152	): DiscoveredCodexFixture {
153	  const candidates = discoverCodexFixtures(upstream);
154	  if (candidates.length === 0) {
155	    throw new Error(
156	      `[${DESIGN_ID}] no codex fixture found in context.upstream — expected at least one ` +
157	        `upstream yield with {codexName, bareLocalPath, baseSha} (the codex-fixture's yield shape).`,
158	    );
159	  }
160	  if (explicitName !== undefined) {
161	    const match = candidates.find((c) => c.codexName === explicitName);
162	    if (!match) {
163	      throw new Error(
164	        `[${DESIGN_ID}] givens.codexName="${explicitName}" did not match any upstream codex ` +
165	          `(seen: ${candidates.map((c) => c.codexName).join(', ')}).`,
166	      );
167	    }
168	    return match;
169	  }
170	  if (candidates.length > 1) {
171	    throw new Error(
172	      `[${DESIGN_ID}] multiple codex fixtures found in context.upstream ` +
173	        `(${candidates.map((c) => c.codexName).join(', ')}); set givens.codexName to disambiguate.`,
174	    );
175	  }
176	  return candidates[0]!;
177	}
178	
179	// ── Git helpers ──────────────────────────────────────────────────────
180	
181	async function git(
182	  args: string[],
183	  cwd: string,
184	  maxBufferBytes: number,
185	): Promise<string> {
186	  try {
187	    const { stdout } = await execFile('git', args, { cwd, maxBuffer: maxBufferBytes });
188	    return stdout;
189	  } catch (err: unknown) {
190	    const e = err as { stderr?: string; message?: string };
191	    throw new Error(`git ${args[0]} failed: ${e.stderr || e.message || 'unknown error'}`);
192	  }
193	}
194	
195	interface CommitMeta {
196	  sha: string;
197	  message: string;
198	  filesChanged: number;
199	  insertions: number;
200	  deletions: number;
201	}
202	
203	/**
204	 * Resolve the head SHA from the bare repo's `main` ref. The codex-
205	 * fixture pushes the base SHA there at setup; the test guild's seal
206	 * flow updates `main` as work commits land.
207	 */
208	async function resolveHeadSha(barePath: string): Promise<string> {
209	  const out = (await git(['rev-parse', 'main'], barePath, 1 * 1024 * 1024)).trim();
210	  if (!/^[0-9a-f]{40}$/i.test(out)) {
211	    throw new Error(`[${DESIGN_ID}] unexpected git rev-parse output: "${out.slice(0, 80)}"`);
212	  }
213	  return out;
214	}
215	
216	/**
217	 * Enumerate commits in `<base>..<head>` ancestry order (oldest → newest).
218	 * Returns just the SHAs.
219	 */
220	async function listCommitShas(barePath: string, base: string, head: string): Promise<string[]> {
221	  if (base === head) return [];
222	  const out = await git(
223	    ['rev-list', '--reverse', `${base}..${head}`],
224	    barePath,
225	    10 * 1024 * 1024,
226	  );
227	  return out
228	    .split('\n')
229	    .map((s) => s.trim())
230	    .filter((s) => s.length > 0);
231	}
232	
233	async function readCommitMessage(barePath: string, sha: string): Promise<string> {
234	  // %B = full message (subject + body, no trailing newline).
235	  const out = await git(
236	    ['show', '--no-patch', '--format=%B', sha],
237	    barePath,
238	    5 * 1024 * 1024,
239	  );
240	  // Strip git's trailing newline; leave embedded newlines alone.
241	  return out.replace(/\n$/, '');
242	}
243	
244	async function readShortStat(barePath: string, sha: string): Promise<{
245	  filesChanged: number;
246	  insertions: number;
247	  deletions: number;
248	}> {
249	  // `git show --shortstat --no-patch --format=` produces empty output: the
250	  // empty `--format=` swallows the shortstat line along with the commit
251	  // header. `git log -1 --shortstat --format=` gives just the shortstat,
252	  // which is what we want.
253	  const out = await git(
254	    ['log', '-1', '--shortstat', '--format=', sha],
255	    barePath,
256	    5 * 1024 * 1024,
257	  );
258	  return parseShortStat(out);
259	}
260	
261	/**
262	 * Parse `git show --shortstat`'s short stat line:
263	 *   " 3 files changed, 12 insertions(+), 4 deletions(-)"
264	 * Tolerates singular/plural, missing-side variants, and extra whitespace.
265	 */
266	export function parseShortStat(line: string): {
267	  filesChanged: number;
268	  insertions: number;
269	  deletions: number;
270	} {
271	  const trimmed = line.trim();
272	  const filesMatch = /(\d+)\s+files?\s+changed/.exec(trimmed);
273	  const insMatch = /(\d+)\s+insertions?\(\+\)/.exec(trimmed);
274	  const delMatch = /(\d+)\s+deletions?\(-\)/.exec(trimmed);
275	  return {
276	    filesChanged: filesMatch ? Number(filesMatch[1]) : 0,
277	    insertions: insMatch ? Number(insMatch[1]) : 0,
278	    deletions: delMatch ? Number(delMatch[1]) : 0,
279	  };
280	}
281	
282	async function readDiff(
283	  barePath: string,
284	  sha: string,
285	  maxBufferBytes: number,
286	): Promise<string> {
287	  // The 10MB cap is enforced after the buffer is in memory; we still
288	  // bound execFile's maxBuffer so a runaway diff doesn't OOM us before
289	  // we get a chance to fail loud.
290	  return git(['show', '--patch', '--format=%H%n', sha], barePath, maxBufferBytes);
291	}
292	
293	// ── run() ────────────────────────────────────────────────────────────
294	
295	async function runGitRange(
296	  rawGivens: Record<string, unknown>,
297	  context: EngineRunContext,
298	): Promise<EngineRunResult> {
299	  const { trialId, codexName: requestedName } = validateGivens(rawGivens);
300	  const codex = selectCodex(context.upstream, requestedName);
301	
302	  const headSha = await resolveHeadSha(codex.bareLocalPath);
303	  const shas = await listCommitShas(codex.bareLocalPath, codex.baseSha, headSha);
304	
305	  const stacks = guild().apparatus<StacksApi>('stacks');
306	  const commits: Book<LabTrialCodexCommit> = stacks.book<LabTrialCodexCommit>(
307	    'laboratory',
308	    LAB_TRIAL_CODEX_COMMITS_BOOK,
309	  );
310	
311	  // execFile maxBuffer: must accommodate the cap plus some overhead
312	  // for `--format=%H%n` lead. Cap+1MB is plenty.
313	  const buffer = PER_DIFF_BYTE_CAP + 1 * 1024 * 1024;
314	
315	  let totalDiffBytes = 0;
316	  let sequence = 0;
317	  for (const sha of shas) {
318	    const message = await readCommitMessage(codex.bareLocalPath, sha);
319	    const stat = await readShortStat(codex.bareLocalPath, sha);
320	    const diffWithHeader = await readDiff(codex.bareLocalPath, sha, buffer);
321	
322	    // The diff output starts with `<sha>\n` (from --format=%H%n) — strip
323	    // it to keep `diff` purely the patch text.
324	    const diff = diffWithHeader.replace(new RegExp(`^${sha}\\n`), '');
325	
326	    const diffBytes = Buffer.byteLength(diff, 'utf8');
327	    if (diffBytes > PER_DIFF_BYTE_CAP) {
328	      throw new Error(
329	        `[${DESIGN_ID}] commit ${sha} diff size ${diffBytes} bytes exceeds the per-diff ` +
330	          `cap of ${PER_DIFF_BYTE_CAP} bytes (10MB). Realistic diffs are <500KB; the cap is a ` +
331	          `tripwire, not a hard limit. Investigate the commit before raising the cap.`,
332	      );
333	    }
334	    totalDiffBytes += diffBytes;
335	
336	    await commits.put({
337	      id: generateId('lcc', 6),
338	      trialId,
339	      sequence,
340	      sha,
341	      message,
342	      filesChanged: stat.filesChanged,
343	      insertions: stat.insertions,
344	      deletions: stat.deletions,
345	      diff,
346	    });
347	    sequence += 1;
348	  }
349	
350	  return {
351	    status: 'completed',
352	    yields: {
353	      codexName: codex.codexName,
354	      baseSha: codex.baseSha,
355	      headSha,
356	      commitCount: shas.length,
357	      totalDiffBytes,
358	      capturedAt: new Date().toISOString(),
359	    },
360	  };
361	}
362	
363	// ── extract() ────────────────────────────────────────────────────────
364	
365	async function extractGitRange(args: ProbeExtractArgs): Promise<ProbeExtractResult> {
366	  const stacks = guild().apparatus<StacksApi>('stacks');
367	  const commits: ReadOnlyBook<LabTrialCodexCommit> = stacks.readBook<LabTrialCodexCommit>(
368	    'laboratory',
369	    LAB_TRIAL_CODEX_COMMITS_BOOK,
370	  );
371	  const rows = await commits.find({
372	    where: [['trialId', '=', args.trialId]],
373	    orderBy: [['sequence', 'asc']],
374	  });
375	
376	  if (rows.length === 0) {
377	    return { files: [] };
378	  }
379	
380	  const exportDir = path.join(args.targetDir, EXTRACT_SUBDIR);
381	  await mkdir(exportDir, { recursive: true });
382	
383	  const manifest = {
384	    commits: rows.map((row) => ({
385	      sequence: row.sequence,
386	      sha: row.sha,
387	      message: row.message.split('\n')[0]!, // subject only in the manifest
388	      filesChanged: row.filesChanged,
389	      insertions: row.insertions,
390	      deletions: row.deletions,
391	      patchFile: patchFileName(row.sequence, row.sha),
392	    })),
393	  };
394	  const manifestText = yamlStringify(manifest);
395	  const manifestRel = path.join(EXTRACT_SUBDIR, COMMITS_MANIFEST_FILE);
396	  const manifestFull = path.join(args.targetDir, manifestRel);
397	  await writeFile(manifestFull, manifestText, 'utf8');
398	
399	  const files: ProbeExtractResult['files'] = [
400	    { path: manifestRel, bytes: Buffer.byteLength(manifestText, 'utf8') },
401	  ];
402	
403	  for (const row of rows) {
404	    const name = patchFileName(row.sequence, row.sha);
405	    const rel = path.join(EXTRACT_SUBDIR, name);
406	    const full = path.join(args.targetDir, rel);
407	    await writeFile(full, row.diff, 'utf8');
408	    files.push({ path: rel, bytes: Buffer.byteLength(row.diff, 'utf8') });
409	  }
410	
411	  return { files };
412	}
413	
414	/**
415	 * Patch file naming: zero-padded sequence + 12-char sha for sortable,
416	 * traceable filenames. `0001-a1b2c3d4e5f6.patch`.
417	 */
418	export function patchFileName(sequence: number, sha: string): string {
419	  return `${String(sequence).padStart(4, '0')}-${sha.slice(0, 12)}.patch`;
420	}
421	
422	export const gitRangeEngine: ProbeEngineDesign = {
423	  id: DESIGN_ID,
424	  run: runGitRange,
425	  extract: extractGitRange,
426	};
427

